#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdint>
#include <vector>
#include <algorithm>
#define CHECK(x) do{ hipError_t e=(x); if(e!=hipSuccess){fprintf(stderr,"err %s\n",hipGetErrorString(e));return 1;}}while(0)

template<int UNROLL>
__global__ void streamRead(const float4* __restrict__ in, size_t n4, float* sink){
    size_t idx=(size_t)blockIdx.x*blockDim.x+threadIdx.x;
    size_t stride=(size_t)gridDim.x*blockDim.x;
    float4 acc=make_float4(0,0,0,0);
    size_t i=idx;
    for(; i + (UNROLL-1)*stride < n4; i += stride*UNROLL){
        #pragma unroll
        for(int u=0;u<UNROLL;u++){ float4 v=in[i+u*stride]; acc.x+=v.x;acc.y+=v.y;acc.z+=v.z;acc.w+=v.w; }
    }
    for(; i<n4; i+=stride){ float4 v=in[i]; acc.x+=v.x;acc.y+=v.y;acc.z+=v.z;acc.w+=v.w; }
    float s=acc.x+acc.y+acc.z+acc.w;
    if(s==-1.0f) sink[idx]=s;
}

template<int U>
double run(const float4* d,size_t n4,float* sink,int blocks,int threads){
    for(int i=0;i<5;i++) hipLaunchKernelGGL(streamRead<U>,dim3(blocks),dim3(threads),0,0,d,n4,sink);
    hipDeviceSynchronize();
    std::vector<float> ts; hipEvent_t a,b; hipEventCreate(&a);hipEventCreate(&b);
    for(int i=0;i<30;i++){ hipEventRecord(a); hipLaunchKernelGGL(streamRead<U>,dim3(blocks),dim3(threads),0,0,d,n4,sink); hipEventRecord(b); hipEventSynchronize(b); float ms; hipEventElapsedTime(&ms,a,b); ts.push_back(ms);}
    std::sort(ts.begin(),ts.end()); return ts[ts.size()/2];
}

int main(){
    size_t bytes=(size_t)4*1024*1024*1024; size_t n4=bytes/16;
    float4* d; float* sink; CHECK(hipMalloc(&d,bytes)); CHECK(hipMalloc(&sink,4096)); hipMemset(d,1,bytes); hipMemset(sink,0,4096);
    hipDeviceProp_t p; hipGetDeviceProperties(&p,0); int cu=p.multiProcessorCount;
    for(int th : {256,512,1024}) for(int mult : {8,16,32,64}){
        int blocks=cu*mult;
        double m1=run<1>(d,n4,sink,blocks,th);
        double m4=run<4>(d,n4,sink,blocks,th);
        double m8=run<8>(d,n4,sink,blocks,th);
        printf("th=%d blk=%d(cu*%d): U1=%.1f U4=%.1f U8=%.1f GB/s\n",th,blocks,mult,
          bytes/(m1*1e-3)/1e9, bytes/(m4*1e-3)/1e9, bytes/(m8*1e-3)/1e9);
    }
    return 0;
}
