#include <hip/hip_runtime.h>
#include <cstdio>
#include <vector>
#include <algorithm>
// nontemporal streaming read
__global__ void ntRead(const float4* __restrict__ in, size_t n4, float* sink){
    size_t idx=(size_t)blockIdx.x*blockDim.x+threadIdx.x;
    size_t stride=(size_t)gridDim.x*blockDim.x;
    float4 acc=make_float4(0,0,0,0);
    for(size_t i=idx;i<n4;i+=stride){
        float4 v=__builtin_nontemporal_load(&in[i]);
        acc.x+=v.x;acc.y+=v.y;acc.z+=v.z;acc.w+=v.w;
    }
    float s=acc.x+acc.y+acc.z+acc.w;
    if(s==-1.0f) sink[idx]=s;
}
double run(const float4* d,size_t n4,float* sink,int blocks,int threads){
    for(int i=0;i<5;i++) hipLaunchKernelGGL(ntRead,dim3(blocks),dim3(threads),0,0,d,n4,sink);
    hipDeviceSynchronize();
    std::vector<float> ts; hipEvent_t a,b; hipEventCreate(&a);hipEventCreate(&b);
    for(int i=0;i<30;i++){hipEventRecord(a);hipLaunchKernelGGL(ntRead,dim3(blocks),dim3(threads),0,0,d,n4,sink);hipEventRecord(b);hipEventSynchronize(b);float ms;hipEventElapsedTime(&ms,a,b);ts.push_back(ms);}
    std::sort(ts.begin(),ts.end());return ts[ts.size()/2];
}
int main(){
    size_t bytes=(size_t)4*1024*1024*1024; size_t n4=bytes/16;
    float4* d; float* sink; hipMalloc(&d,bytes); hipMalloc(&sink,4096); hipMemset(d,1,bytes);
    hipDeviceProp_t p; hipGetDeviceProperties(&p,0); int cu=p.multiProcessorCount;
    for(int th:{256,512,1024})for(int mult:{8,16,32}){
        int blocks=cu*mult; double m=run(d,n4,sink,blocks,th);
