#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstdlib>
#include <vector>
#include <algorithm>

#define CHECK(x) do { hipError_t e = (x); if (e != hipSuccess) { \
  fprintf(stderr, "HIP error %s at %s:%d\n", hipGetErrorString(e), __FILE__, __LINE__); \
  return 1; } } while(0)

typedef float float4v __attribute__((ext_vector_type(4)));

// Read-only streaming kernel: grid-stride loop of nontemporal (cache-bypassing)
// vectorized loads over the whole buffer, reduced into a register accumulator.
// The accumulator is kept live via an effectively-never-taken sink write so the
// compiler cannot eliminate the loads.
__global__ void streamRead(const float4v* __restrict__ in, size_t n4, float* sink) {
    size_t idx = (size_t)blockIdx.x * blockDim.x + threadIdx.x;
    size_t stride = (size_t)gridDim.x * blockDim.x;
    float4v acc = {0.f, 0.f, 0.f, 0.f};
    for (size_t i = idx; i < n4; i += stride) {
        acc += __builtin_nontemporal_load(&in[i]);
    }
    float s = acc.x + acc.y + acc.z + acc.w;
    if (s == -1.0f) sink[idx] = s;
}

int main(int argc, char** argv) {
    // ~4 GiB working set — far larger than any cache, so reads hit HBM.
    size_t bytes = (size_t)4 * 1024 * 1024 * 1024;
    if (argc > 1) bytes = (size_t)atoll(argv[1]);
    size_t n4 = bytes / sizeof(float4v);
    bytes = n4 * sizeof(float4v); // exact bytes read in one pass over the buffer

    float4v* d_in = nullptr;
    float* d_sink = nullptr;
    CHECK(hipMalloc(&d_in, bytes));
    CHECK(hipMalloc(&d_sink, 4096 * sizeof(float)));
    CHECK(hipMemset(d_in, 1, bytes));
    CHECK(hipMemset(d_sink, 0, 4096 * sizeof(float)));

    int dev; CHECK(hipGetDevice(&dev));
    hipDeviceProp_t prop; CHECK(hipGetDeviceProperties(&prop, dev));

    int threads = 1024;
    int blocks  = prop.multiProcessorCount * 32; // heavily oversubscribe to saturate HBM

    // Warmup
    for (int i = 0; i < 10; ++i)
        hipLaunchKernelGGL(streamRead, dim3(blocks), dim3(threads), 0, 0, d_in, n4, d_sink);
    CHECK(hipDeviceSynchronize());

    const int iters = 50;
    std::vector<float> times;
    times.reserve(iters);
    hipEvent_t start, stop;
    CHECK(hipEventCreate(&start));
    CHECK(hipEventCreate(&stop));

    for (int i = 0; i < iters; ++i) {
        CHECK(hipEventRecord(start));
        hipLaunchKernelGGL(streamRead, dim3(blocks), dim3(threads), 0, 0, d_in, n4, d_sink);
        CHECK(hipEventRecord(stop));
        CHECK(hipEventSynchronize(stop));
        float ms = 0.f;
        CHECK(hipEventElapsedTime(&ms, start, stop));
        times.push_back(ms);
    }

    std::sort(times.begin(), times.end());
    float median_ms = times[times.size() / 2];
    double gbps = (double)bytes / (median_ms * 1e-3) / 1e9;

    printf("HBM_BANDWIDTH_GBPS=%.2f\n", gbps);
    printf("buffer_bytes=%zu\n", bytes);

    (void)hipFree(d_in);
    (void)hipFree(d_sink);
    (void)hipEventDestroy(start);
    (void)hipEventDestroy(stop);
    return 0;
}

