// Time several batches; within each batch launch the kernel back-to-back so
// per-dispatch host/event overhead is amortized. This keeps the measured
// per-kernel time close to pure GPU execution time even under a profiler,
// and we take the median batch to reject outliers.
const int batches = 10;
const int per_batch = 5;
std::vector<double> per_kernel_ms;
per_kernel_ms.reserve(batches);
hipEvent_t start, stop;
CHECK(hipEventCreate(&start));
CHECK(hipEventCreate(&stop));

for (int b = 0; b < batches; ++b) {
    CHECK(hipEventRecord(start));
    for (int i = 0; i < per_batch; ++i)
        hipLaunchKernelGGL(streamRead, dim3(blocks), dim3(threads), 0, 0, d_in, n4, d_sink);
    CHECK(hipEventRecord(stop));
    CHECK(hipEventSynchronize(stop));
    float ms = 0.f;
    CHECK(hipEventElapsedTime(&ms, start, stop));
    per_kernel_ms.push_back((double)ms / per_batch);
}

std::sort(per_kernel_ms.begin(), per_kernel_ms.end());
double median_ms = per_kernel_ms[per_kernel_ms.size() / 2];
double gbps = (double)bytes / (median_ms * 1e-3) / 1e9;

